+
+    conn.execute("INSERT INTO dst (y, x) SELECT a, b FROM src;").unwrap();
+    
+    let rows2 = conn.query("SELECT x, y FROM dst;").unwrap();
+    println!("dst row 0: {:?}", rows2[0].values());
+}
